What does this program print when given input `4 5`?

```cpp
#include <iostream>

int area(int w, int h) { return w * h; }
void printArea(int w, int h) {
    std::cout << "Area: " << area(w, h) << "\n";
}

int main() {
    int w, h;
    std::cin >> w >> h;
    printArea(w, h);
    return 0;
}
```

